// src/pages/MaterialsPage.js
import React from 'react';
import { useParams, useNavigate } from 'react-router-dom';

const MaterialsPage = () => {
  const { courseId, yearId, semId, subjectId } = useParams();
  const navigate = useNavigate();
  
  const handleBack = () => {
    navigate(`/course/${courseId}/year/${yearId}/sem/${semId}`);
  };
  
  return (
    <div style={styles.container}>
      <button onClick={handleBack} style={styles.backButton}>
        ← Back to Subjects
      </button>
      
      <div style={styles.header}>
        <h1>Subject {subjectId} - Study Materials</h1>
        <p>Syllabus, Notes, PYQs, and more</p>
      </div>
      
      <div style={styles.materialsGrid}>
        {['Syllabus', 'Notes', 'PYQs', 'Important Questions', 'Lab Manuals'].map((material, index) => (
          <div key={index} style={styles.materialCard}>
            <h3>{material}</h3>
            <p>Download or view {material.toLowerCase()}</p>
            <div style={styles.actions}>
              <button style={styles.downloadButton}>📥 Download</button>
              <button style={styles.previewButton}>👁️ Preview</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

const styles = {
  container: {
    maxWidth: '1200px',
    margin: '0 auto',
    padding: '2rem 1rem',
    minHeight: '100vh'
  },
  backButton: {
    padding: '0.75rem 1.5rem',
    background: '#4f46e5',
    color: 'white',
    border: 'none',
    borderRadius: '8px',
    cursor: 'pointer',
    marginBottom: '2rem'
  },
  header: {
    textAlign: 'center',
    marginBottom: '3rem',
    padding: '2rem',
    background: 'white',
    borderRadius: '15px',
    boxShadow: '0 5px 15px rgba(0,0,0,0.05)'
  },
  materialsGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))',
    gap: '1.5rem'
  },
  materialCard: {
    background: 'white',
    padding: '1.5rem',
    borderRadius: '12px',
    boxShadow: '0 5px 15px rgba(0,0,0,0.05)',
    textAlign: 'center'
  },
  actions: {
    display: 'flex',
    gap: '0.5rem',
    marginTop: '1rem'
  },
  downloadButton: {
    flex: 2,
    padding: '0.75rem',
    background: 'linear-gradient(90deg, #10b981, #34d399)',
    color: 'white',
    border: 'none',
    borderRadius: '6px',
    cursor: 'pointer'
  },
  previewButton: {
    flex: 1,
    padding: '0.75rem',
    background: '#f3f4f6',
    color: '#4b5563',
    border: '1px solid #d1d5db',
    borderRadius: '6px',
    cursor: 'pointer'
  }
};

export default MaterialsPage;
